#include <stdio.h>
#include <stdlib.h>

int lower_bound(int *arr, int size, int target) {
    int l = 0, r = size;
    while (l < r) {
        int m = (l + r) / 2;
        if (arr[m] < target) l = m + 1; else r = m;
    }
    return l;
}

int lis_length(int *seq, int n) {
    int *tail = (int*)malloc(n * sizeof(int));
    int len = 0;
    for (int i = 0; i < n; ++i) {
        int pos = lower_bound(tail, len, seq[i]);
        tail[pos] = seq[i];
        if (pos == len) ++len;
    }
    free(tail);
    return len;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int best = 1;
        int *rot = (int*)malloc(N * sizeof(int));
        for (int start = 0; start < N; ++start) {
            for (int i = 0; i < N; ++i) rot[i] = a[(start + i) % N];
            int cur = lis_length(rot, N);
            if (cur > best) best = cur;
        }
        printf("%d\n", best);
        free(a);
        free(rot);
    }
    return 0;
}

