#include <bits/stdc++.h>
using namespace std;

int lisLength(const vector<int>& v) {
    vector<int> tail;
    tail.reserve(v.size());
    for (int x : v) {
        auto it = lower_bound(tail.begin(), tail.end(), x);
        if (it == tail.end()) tail.push_back(x);
        else *it = x;
    }
    return (int)tail.size();
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        for (int &x : a) cin >> x;
        int answer = 1;
        vector<int> cur(N);
        for (int start = 0; start < N; ++start) {
            for (int i = 0; i < N; ++i) cur[i] = a[(start + i) % N];
            answer = max(answer, lisLength(cur));
        }
        cout << answer << '\n';
    }
    return 0;
}

