import sys
from bisect import bisect_left

def lis_length(seq):
    tail = []
    for x in seq:
        i = bisect_left(tail, x)
        if i == len(tail):
            tail.append(x)
        else:
            tail[i] = x
    return len(tail)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        best = 1
        for start in range(N):
            cur = a[start:] + a[:start]
            best = max(best, lis_length(cur))
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

